Sure, I’d be happy to help! Let’s break it into steps. First, you’ll need to set up your Express.js application, connect to an SQLite database, and implement JWT-based authentication. I’ll walk you through the key parts of the project.

### Step 1: Initialize a new project
Begin by creating a new Node.js project and installing the dependencies:
```bash
npm init -y
npm install express sqlite3 jsonwebtoken bcryptjs body-parser dotenv
```

### Step 2: Set up the SQLite connection
Create a file, `db.js`, to manage your SQLite database connection:
```javascript
const sqlite3 = require('sqlite3').verbose();

const db = new sqlite3.Database('./todo.db', (err) => {
  if (err) {
    console.error('Error opening database:', err.message);
  } else {
    console.log('Connected to the SQLite database.');
    db.run(
      `CREATE TABLE IF NOT EXISTS users (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        username TEXT UNIQUE,
        password TEXT
      )`
    );
    db.run(
      `CREATE TABLE IF NOT EXISTS todos (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        user_id INTEGER,
        title TEXT,
        completed INTEGER DEFAULT 0,
        FOREIGN KEY(user_id) REFERENCES users(id)
      )`
    );
  }
});

module.exports = db;
```

### Step 3: Implement user authentication
Create a route to register users and handle login using JWT. For example, in your `index.js`:
```javascript
const express = require('express');
const bodyParser = require('body-parser');
const bcrypt = require('bcryptjs');
const jwt = require('jsonwebtoken');
const db = require('./db');
require('dotenv').config();

const app = express();
const PORT = 3000;
app.use(bodyParser.json());

const SECRET_KEY = process.env.SECRET_KEY || 'your_secret_key_here';

// User registration route
app.post('/register', (req, res) => {
  const { username, password } = req.body;

  if (!username || !password) {
    return res.status(400).json({ error: 'Username and password are required.' });
  }

  const hashedPassword = bcrypt.hashSync(password, 10);

  db.run(
    `INSERT INTO users (username, password) VALUES (?, ?)`,
    [username, hashedPassword],
    function (err) {
      if (err) {
        return res.status(400).json({ error: 'User already exists.' });
      }
      res.status(201).json({ message: 'User registered successfully!' });
    }
  );
});

// User login route
app.post('/login', (req, res) => {
  const { username, password } = req.body;

  db.get(`SELECT * FROM users WHERE username = ?`, [username], (err, user) => {
    if (err || !user) {
      return res.status(400).json({ error: 'Invalid credentials.' });
    }

    const isPasswordValid = bcrypt.compareSync(password, user.password);

    if (!isPasswordValid) {
      return res.status(400).json({ error: 'Invalid credentials.' });
    }

    const token = jwt.sign({ id: user.id, username: user.username }, SECRET_KEY, {
      expiresIn: '1h',
    });

    res.json({ message: 'Logged in successfully!', token });
  });
});
```

### Step 4: CRUD for To-Do items
After implementing authentication, add protected routes for creating, reading, updating, and deleting To-Do items. Protect these routes with a middleware to verify JWTs.

Middleware for verifying the JWT (add this in your `index.js`):
```javascript
function authenticateToken(req, res, next) {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) return res.status(401).json({ error: 'Access denied.' });

  jwt.verify(token, SECRET_KEY, (err, user) => {
    if (err) return res.status(403).json({ error: 'Invalid token.' });
    req.user = user;
    next();
  });
}
```

Routes for managing To-Dos:
```javascript
// Create a To-Do
app.post('/todos', authenticateToken, (req, res) => {
  const { title } = req.body;
  const userId = req.user.id;

  db.run(
    `INSERT INTO todos (user_id, title) VALUES (?, ?)`,
    [userId, title],
    function (err) {
      if (err) {
        return res.status(400).json({ error: 'Failed to create To-Do.' });
      }
      res.status(201).json({ id: this.lastID, title, completed: false });
    }
  );
});

// Get user To-Dos
app.get('/todos', authenticateToken, (req, res) => {
  const userId = req.user.id;

  db.all(`SELECT * FROM todos WHERE user_id = ?`, [userId], (err, rows) => {
    if (err) {
      return res.status(400).json({ error: 'Failed to fetch To-Dos.' });
    }
    res.json(rows);
  });
});

// Update a To-Do
app.put('/todos/:id', authenticateToken, (req, res) => {
  const { id } = req.params;
  const { title, completed } = req.body;
  const userId = req.user.id;

  db.run(
    `UPDATE todos SET title = ?, completed = ? WHERE id = ? AND user_id = ?`,
    [title, completed ? 1 : 0, id, userId],
    function (err) {
      if (err || this.changes === 0) {
        return res.status(400).json({ error: 'Failed to update To-Do or unauthorized.' });
      }
      res.json({ message: 'To-Do updated successfully!' });
    }
  );
});

// Delete a To-Do
app.delete('/todos/:id', authenticateToken, (req, res) => {
  const { id } = req.params;
  const userId = req.user.id;

  db.run(`DELETE FROM todos WHERE id = ? AND user_id = ?`, [id, userId], function (err) {
    if (err || this.changes === 0) {
      return res.status(400).json({ error: 'Failed to delete To-Do or unauthorized.' });
    }
    res.json({ message: 'To-Do deleted successfully!' });
  });
});
```

### Step 5: Start the server
Finally, start the server:
```javascript
app.listen(PORT, () => {
  console.log(`Server is running on http://localhost:${PORT}`);
});
```

This should give you a basic functional To-Do List app with user authentication. Let me know if you need help with extending or testing this!

Great question! To add a 'high priority' flag to your To-Dos, you'll need to modify the database schema, update your API routes, and adjust the logic accordingly. Here’s how to do it:

### Step 1: Update the database schema
You need to add a `priority` column to the `todos` table. Run this SQL command to alter your database:
```sql
ALTER TABLE todos ADD COLUMN priority INTEGER DEFAULT 0;
```
This adds a `priority` column where `0` represents normal priority, and `1` represents high priority.

If you want to incorporate this change dynamically in your app, you could modify the database initialization code in `db.js` to include this column or run the above SQL manually using an SQLite tool.

### Step 2: Update the API routes
You’ll now include the `priority` field in the relevant API endpoints. Here’s how:

#### Create a To-Do with priority:
Update the `/todos` POST route:
```javascript
app.post('/todos', authenticateToken, (req, res) => {
  const { title, priority } = req.body;
  const userId = req.user.id;

  const validatedPriority = priority === 1 ? 1 : 0; // Ensure the priority is valid (0 or 1)

  db.run(
    `INSERT INTO todos (user_id, title, priority) VALUES (?, ?, ?)`,
    [userId, title, validatedPriority],
    function (err) {
      if (err) {
        return res.status(400).json({ error: 'Failed to create To-Do.' });
      }
      res.status(201).json({ id: this.lastID, title, completed: false, priority: validatedPriority });
    }
  );
});
```

#### Fetch To-Dos with priority:
Update the `/todos` GET route to include the `priority` field in the response:
```javascript
app.get('/todos', authenticateToken, (req, res) => {
  const userId = req.user.id;

  db.all(`SELECT * FROM todos WHERE user_id = ?`, [userId], (err, rows) => {
    if (err) {
      return res.status(400).json({ error: 'Failed to fetch To-Dos.' });
    }
    res.json(rows.map(todo => ({
      ...todo,
      priority: todo.priority === 1 // Return boolean for clarity
    })));
  });
});
```

#### Update To-Do priority:
Update the `/todos/:id` PUT route to allow modifying the priority:
```javascript
app.put('/todos/:id', authenticateToken, (req, res) => {
  const { id } = req.params;
  const { title, completed, priority } = req.body;
  const userId = req.user.id;

  const validatedPriority = priority === 1 ? 1 : 0; // Ensure valid priority

  db.run(
    `UPDATE todos SET title = ?, completed = ?, priority = ? WHERE id = ? AND user_id = ?`,
    [title, completed ? 1 : 0, validatedPriority, id, userId],
    function (err) {
      if (err || this.changes === 0) {
        return res.status(400).json({ error: 'Failed to update To-Do or unauthorized.' });
      }
      res.json({ message: 'To-Do updated successfully!' });
    }
  );
});
```

### Step 3: Testing your extensions
Once the changes are implemented, test the following:
1. **Create a To-Do with priority:**
   ```bash
   curl -X POST -H "Authorization: Bearer <your_token_here>" -H "Content-Type: application/json" \
   -d '{"title": "High priority task", "priority": 1}' http://localhost:3000/todos
   ```
2. **Fetch To-Dos:**
   ```bash
   curl -X GET -H "Authorization: Bearer <your_token_here>" http://localhost:3000/todos
   ```
3. **Update a To-Do’s priority:**
   ```bash
   curl -X PUT -H "Authorization: Bearer <your_token_here>" -H "Content-Type: application/json" \
   -d '{"priority": 1}' http://localhost:3000/todos/1
   ```

This will allow users to mark To-Dos as high priority. Let me know if you encounter any issues!

To ensure that high-priority To-Do items are always returned first, you can modify the SQL query in your `/todos` GET route by adding an `ORDER BY` clause. This will sort the results based on the `priority` column, placing high-priority items (`priority = 1`) before normal ones (`priority = 0`). Here's how you can do it:

### Updated `/todos` GET Route
Modify the route like this:

```javascript
app.get('/todos', authenticateToken, (req, res) => {
  const userId = req.user.id;

  db.all(
    `SELECT * FROM todos WHERE user_id = ? ORDER BY priority DESC, id ASC`,
    [userId],
    (err, rows) => {
      if (err) {
        return res.status(400).json({ error: 'Failed to fetch To-Dos.' });
      }
      res.json(rows.map(todo => ({
        ...todo,
        priority: todo.priority === 1 // Convert priority to a boolean for clarity
      })));
    }
  );
});
```

### Explanation of the Query
- `ORDER BY priority DESC`: This ensures that items with `priority = 1` (high priority) appear first.
- `id ASC`: This ensures that items with the same priority are sorted by their `id` in ascending order, so they appear in the order they were created.

### Testing the Updated Route
Try fetching the To-Dos again to confirm high-priority items appear first:
```bash
curl -X GET -H "Authorization: Bearer <your_token_here>" http://localhost:3000/todos
```
You should see the high-priority To-Dos sorted to the top of the list.

