Absolutely! To enable users to download the filtered CSV as a file, you can return a `StreamingResponse` in FastAPI. This allows you to stream the CSV file content to the client, so they can download it directly. Below is the updated code with an added `download-csv` endpoint:

```python
from fastapi import FastAPI, File, UploadFile, HTTPException
from pydantic import BaseModel
from fastapi.responses import StreamingResponse
import pandas as pd
from io import BytesIO

app = FastAPI()

class FilterCondition(BaseModel):
    column: str
    operator: str
    value: str

@app.post("/process-csv/")
async def process_csv(
    file: UploadFile = File(...), 
    conditions: list[FilterCondition] = []
):
    try:
        contents = await file.read()
        df = pd.read_csv(BytesIO(contents))

        for condition in conditions:
            if condition.column not in df.columns:
                raise HTTPException(status_code=400, detail=f"Column '{condition.column}' does not exist in the CSV.")

            if condition.operator == '==':
                df = df[df[condition.column] == condition.value]
            elif condition.operator == '>':
                df = df[df[condition.column].astype(float) > float(condition.value)]
            elif condition.operator == '<':
                df = df[df[condition.column].astype(float) < float(condition.value)]
            else:
                raise HTTPException(status_code=400, detail=f"Unsupported operator '{condition.operator}'.")

        output = df.to_csv(index=False)
        return {"filtered_data": output}

    except Exception as e:
        raise HTTPException(status_code=500, detail=f"An error occurred while processing the file: {str(e)}")

@app.post("/download-csv/")
async def download_csv(
    file: UploadFile = File(...), 
    conditions: list[FilterCondition] = []
):
    try:
        contents = await file.read()
        df = pd.read_csv(BytesIO(contents))

        for condition in conditions:
            if condition.column not in df.columns:
                raise HTTPException(status_code=400, detail=f"Column '{condition.column}' does not exist in the CSV.")

            if condition.operator == '==':
                df = df[df[condition.column] == condition.value]
            elif condition.operator == '>':
                df = df[df[condition.column].astype(float) > float(condition.value)]
            elif condition.operator == '<':
                df = df[df[condition.column].astype(float) < float(condition.value)]
            else:
                raise HTTPException(status_code=400, detail=f"Unsupported operator '{condition.operator}'.")

        # Convert the filtered DataFrame to CSV and prepare a file-like object
        output = BytesIO()
        df.to_csv(output, index=False)
        output.seek(0)

        # Stream the response as a downloadable file
        return StreamingResponse(
            output, 
            media_type="text/csv",
            headers={"Content-Disposition": "attachment; filename=filtered_output.csv"}
        )

    except Exception as e:
        raise HTTPException(status_code=500, detail=f"An error occurred while processing the file: {str(e)}")

@app.get("/")
def read_root():
    return {"message": "Welcome to the enhanced CSV processing API!"}
```

### Key Changes:
1. **`StreamingResponse`:** This is used in the `/download-csv/` endpoint to send the filtered CSV as a downloadable file. The `BytesIO` object serves as the in-memory storage for the CSV data.
2. **New Endpoint:** The `/download-csv/` endpoint behaves like the `/process-csv/` endpoint but streams the output instead of embedding it in the JSON response.
3. **Content-Disposition Header:** This ensures the client’s browser prompts for a file download with the filename `filtered_output.csv`.

### Example Request for `/download-csv/`:
Send a `POST` request to `/download-csv/` with the same structure for conditions as the `/process-csv/` endpoint, but the response will now trigger a CSV file download instead of returning JSON data.

