<script>
const API_BASE = 'http://localhost:8000/api/v1';
let chartInstances = {};
let currentData = null;

// ==================== 初始化 ====================
async function init() {
    chartInstances.trend = echarts.init(document.getElementById('trendChart'));
    chartInstances.category = echarts.init(document.getElementById('categoryChart'));
    chartInstances.topProducts = echarts.init(document.getElementById('topProductsChart'));
    chartInstances.drilldown = echarts.init(document.getElementById('drilldownChart'));

    // 分类饼图点击下钻
    chartInstances.category.on('click', function(params) {
