    });

    window.addEventListener('resize', () => {
        Object.values(chartInstances).forEach(c => c.resize());
    });

    await loadDashboard();
}

// ==================== 数据加载 ====================
async function loadDashboard() {
    const start = document.getElementById('startDate').value;
    const end = document.getElementById('endDate').value;

    try {
        const [trendRes, categoryRes, topRes] = await Promise.all([
            fetch(`${API_BASE}/sales/trend?start_date=${start}&end_date=${end}`),
            fetch(`${API_BASE}/sales/by-category?start_date=${start}&end_date=${end}`),
            fetch(`${API_BASE}/sales/filter?start_date=${start}&end_date=${end}&sort_by=revenue&limit=10`)
        ]);

        const trendData = await trendRes.json();
        const categoryData = await categoryRes.json();
        const topData = await topRes.json();
        currentData = { trend: trendData, category: categoryData, top: topData };

        renderTrend(trendData);
        renderCategory(categoryData);
        renderTopProducts(topData);
    } catch (err) {
        console.error('加载数据失败:', err);
    }
}

// ==================== 图表渲染 ====================
function renderTrend(data) {
    const dates = data.map(d => d.date);
    const revenues = data.map(d => d.revenue);
    const orders = data.map(d => d.order_count);

    chartInstances.trend.setOption({
        tooltip: { trigger: 'axis', axisPointer: { type: 'cross' } },
        legend: { data: ['销售额', '订单数'] },
        xAxis: { type: 'category', data: dates, axisLabel: { rotate: 45 } },
        yAxis: [
            { type: 'value', name: '销售额(元)', axisLabel: { formatter: v => (v/10000).toFixed(0)+'万' } },
            { type: 'value', name: '订单数', position: 'right' }
        ],
        series: [
            { name: '销售额', type: 'line', data: revenues, smooth: true, areaStyle: { opacity: 0.15 }, itemStyle: { color: '#667eea' } },
            { name: '订单数', type: 'bar', yAxisIndex: 1, data: orders, itemStyle: { color: '#ffc069', opacity: 0.6 }, barMaxWidth: 20 }
        ],
        dataZoom: [{ type: 'slider', start: 0, end: 100 }]
    });
}

function renderCategory(data) {
    const items = data.map(d => ({ name: d.category, value: d.revenue }));
    chartInstances.category.setOption({
        tooltip: { trigger: 'item', formatter: '{b}: ¥{c} ({d}%)' },
        legend: { orient: 'vertical', right: 10, top: 'center' },
        series: [{
            type: 'pie', radius: ['40%', '70%'], center: ['40%', '50%'],
            label: { formatter: '{b}\n{d}%' },
            emphasis: { label: { fontSize: 16, fontWeight: 'bold' } },
            data: items
        }]
    });
}

function renderTopProducts(data) {
    const items = (data.items || data).slice(0, 10).reverse();
    chartInstances.topProducts.setOption({
        tooltip: { trigger: 'axis' },
        xAxis: { type: 'value', axisLabel: { formatter: v => (v/10000).toFixed(0)+'万' } },
        yAxis: { type: 'category', data: items.map(d => d.product_name), axisLabel: { width: 100, overflow: 'truncate' } },
        series: [{
            type: 'bar', data: items.map(d => d.revenue),
            itemStyle: { color: new echarts.graphic.LinearGradient(0,0,1,0, [{offset:0,color:'#667eea'},{offset:1,color:'#764ba2'}]) },
            label: { show: true, position: 'right', formatter: p => '¥'+(p.value/10000).toFixed(1)+'万' }
        }]
    });
}

// ==================== 日期筛选 ====================
function applyDateFilter() { loadDashboard(); }

function setQuickRange(type) {
    const now = new Date();
    let start, end;
    if (type === 'month') {
        start = new Date(now.getFullYear(), now.getMonth(), 1);
        end = new Date(now.getFullYear(), now.getMonth() + 1, 0);
    } else if (type === 'quarter') {
        const q = Math.floor(now.getMonth() / 3);
        start = new Date(now.getFullYear(), q * 3, 1);
        end = new Date(now.getFullYear(), q * 3 + 3, 0);
    } else {
        start = new Date(now.getFullYear(), 0, 1);
        end = new Date(now.getFullYear(), 11, 31);
    }
    document.getElementById('startDate').value = start.toISOString().slice(0, 10);
    document.getElementById('endDate').value = end.toISOString().slice(0, 10);
    loadDashboard();
}

// ==================== 下钻 ====================
async function loadDrilldown(category) {
    document.getElementById('drilldownModal').style.display = 'flex';
