    const end = document.getElementById('endDate').value;

    try {
        const res = await fetch(`${API_BASE}/sales/filter?category=${encodeURIComponent(category)}&start_date=${start}&end_date=${end}&sort_by=revenue&limit=20`);
        const data = await res.json();
        const items = (data.items || data).reverse();

        chartInstances.drilldown.setOption({
            title: { text: `${category}分类 — TOP 商品`, left: 'center' },
            tooltip: { trigger: 'axis' },
            xAxis: { type: 'value' },
            yAxis: { type: 'category', data: items.map(d => d.product_name) },
            series: [{
                type: 'bar', data: items.map(d => d.revenue),
                label: { show: true, position: 'right', formatter: p => '¥'+p.value.toLocaleString() },
                itemStyle: { color: '#764ba2' }
            }]
        });
    } catch(err) { console.error('下钻加载失败:', err); }
}

function closeDrilldown() { document.getElementById('drilldownModal').style.display = 'none'; }

// ==================== 环比对比 ====================
function toggleCompare() {
    const show = document.getElementById('compareToggle').checked;
    document.getElementById('compare-section').style.display = show ? 'grid' : 'none';
    if (show) loadCompare();
}

async function loadCompare() {
    const now = new Date();
    const thisStart = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().slice(0,10);
    const thisEnd = new Date(now.getFullYear(), now.getMonth()+1, 0).toISOString().slice(0,10);
    const lastStart = new Date(now.getFullYear(), now.getMonth()-1, 1).toISOString().slice(0,10);
    const lastEnd = new Date(now.getFullYear(), now.getMonth(), 0).toISOString().slice(0,10);

    try {
        const [thisRes, lastRes] = await Promise.all([
            fetch(`${API_BASE}/sales/overview?start_date=${thisStart}&end_date=${thisEnd}`),
            fetch(`${API_BASE}/sales/overview?start_date=${lastStart}&end_date=${lastEnd}`)
        ]);
        const thisMonth = await thisRes.json();
        const lastMonth = await lastRes.json();

        updateCompareCard('cmpRevenue', 'cmpRevenueChange', thisMonth.total_revenue, lastMonth.total_revenue, v => '¥'+(v/10000).toFixed(1)+'万');
        updateCompareCard('cmpOrders', 'cmpOrdersChange', thisMonth.total_orders, lastMonth.total_orders, v => v.toLocaleString());
        updateCompareCard('cmpAvg', 'cmpAvgChange', thisMonth.avg_order_value, lastMonth.avg_order_value, v => '¥'+v.toFixed(0));
        updateCompareCard('cmpCustomers', 'cmpCustomersChange', thisMonth.unique_customers, lastMonth.unique_customers, v => v.toLocaleString());
    } catch(err) { console.error('环比数据加载失败:', err); }
}

function updateCompareCard(valueId, changeId, current, previous, formatter) {
    document.getElementById(valueId).textContent = formatter(current);
    const pct = previous > 0 ? ((current - previous) / previous * 100).toFixed(1) : '--';
    const el = document.getElementById(changeId);
    const isUp = current >= previous;
    el.textContent = `${isUp ? '↑' : '↓'} ${Math.abs(pct)}%`;
    el.className = `change ${isUp ? 'up' : 'down'}`;
}

// ==================== 导出 ====================
function toggleExportMenu() {
    const menu = document.getElementById('export-menu');
    menu.style.display = menu.style.display === 'block' ? 'none' : 'block';
}

function exportChartPNG(chartId) {
    const chart = chartInstances[chartId.replace('Chart', '').toLowerCase()] || chartInstances[chartId];
    if (!chart) return;
    const url = chart.getDataURL({ type: 'png', pixelRatio: 2, backgroundColor: '#fff' });
    const a = document.createElement('a');
    a.href = url;
    a.download = `${chartId}_${new Date().toISOString().slice(0,10)}.png`;
    a.click();
    document.getElementById('export-menu').style.display = 'none';
}

function exportDataCSV() {
    if (!currentData || !currentData.trend) return;
    let csv = 'Date,Revenue,OrderCount\n';
    currentData.trend.forEach(d => { csv += `${d.date},${d.revenue},${d.order_count}\n`; });
    const blob = new Blob(['\uFEFF' + csv], { type: 'text/csv;charset=utf-8;' });
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `sales_data_${new Date().toISOString().slice(0,10)}.csv`;
    a.click();
    document.getElementById('export-menu').style.display = 'none';
}

document.addEventListener('click', e => {
    if (!e.target.closest('#export-menu') && !e.target.closest('[onclick="toggleExportMenu()"]')) {
        document.getElementById('export-menu').style.display = 'none';
    }
});

// 初始化
document.addEventListener('DOMContentLoaded', init);
</script>
</body>
</html>
```Interactive Enhancements Summary:
1. **Date Range Picker** — Supports manual input and quick buttons (This Month/This Quarter/Full Year). After filtering, all charts refresh automatically.
2. **Category Drill-Down** — Clicking any category in the pie chart opens a modal displaying a bar chart of the TOP 20 products within that category.
3. **Month-over-Month Comparison** — When selected, displays comparison cards for sales, order count, average order value, and customer count for this month vs. last month, including percentage change.
4. **Export Functionality** — Charts can be exported as 2x high-definition PNGs; data can be exported as UTF-8 CSV files with BOM header (Excel compatible).

Sure! Building a documentation site with Next.js, MDX, and Tailwind CSS follows many of the same principles as creating a blog. Here's a step-by-step guide to get you started:

### 1. Initialize a New Next.js Project
Run the following commands to set up your project:
```bash
npx create-next-app@latest my-docs-site --typescript
cd my-docs-site
```

### 2. Install Necessary Dependencies
You’ll need MDX and Tailwind CSS:
```bash
npm install @next/mdx @mdx-js/loader
npm install -D tailwindcss postcss autoprefixer
npx tailwindcss init
```

Once installed, configure Tailwind by updating the content section of your `tailwind.config.js`:
```js
/** @type {import('tailwindcss').Config} */
module.exports = {
  content: ["./pages/**/*.{js,ts,jsx,tsx}", "./components/**/*.{js,ts,jsx,tsx}", "./docs/**/*.{md,mdx}"],
  theme: {
    extend: {},
  },
  plugins: [],
};
```

### 3. Configure MDX Support
Create or update your `next.config.js` to enable MDX in your Next.js project:
```js
const withMDX = require("@next/mdx")({
  extension: /\.mdx$/,
});

module.exports = withMDX({
  pageExtensions: ["js", "jsx", "ts", "tsx", "md", "mdx"],
});
```

### 4. Set Up a Basic Folder Structure
Create the following structure for your documentation content:
```
my-docs-site/
├── docs/
│   ├── index.mdx
│   ├── getting-started.mdx
│   ├── advanced-topics.mdx
│
├── pages/
│   ├── index.tsx
│
├── components/
│   └── layout.tsx
```

For example, your `docs/index.mdx` might look like this:
```mdx
---
title: "Welcome"
---

# Welcome to My Docs Site

This is an example of a documentation page built with MDX and Tailwind CSS.
```

### 5. Create a Page to Render Documentation Content
You can create a `docs` page that dynamically loads MDX content. Here’s an example (`pages/docs/[slug].tsx`):
```tsx
import fs from "fs";
import path from "path";
import matter from "gray-matter";
import { GetStaticPaths, GetStaticProps } from "next";
import { MDXRemote, MDXRemoteSerializeResult } from "next-mdx-remote";
import { serialize } from "next-mdx-remote/serialize";

const DOCS_PATH = path.join(process.cwd(), "docs");

export const getStaticPaths: GetStaticPaths = async () => {
  const filenames = fs.readdirSync(DOCS_PATH);
  const paths = filenames.map((filename) => ({
    params: { slug: filename.replace(/\.mdx?$/, "") },
  }));
  return { paths, fallback: false };
};

export const getStaticProps: GetStaticProps = async ({ params }) => {
  const slug = params?.slug as string;
  const filePath = path.join(DOCS_PATH, `${slug}.mdx`);
  const source = fs.readFileSync(filePath);
  const { content, data } = matter(source);
  const mdxSource = await serialize(content);

  return {
    props: {
      source: mdxSource,
      frontMatter: data,
    },
  };
};

const DocPage = ({ source, frontMatter }: { source: MDXRemoteSerializeResult; frontMatter: any }) => {
  return (
    <div className="prose mx-auto mt-8">
      <h1>{frontMatter.title}</h1>
      <MDXRemote {...source} />
    </div>
  );
};

export default DocPage;
```

### 6. Add Styling with Tailwind CSS
Make sure you include Tailwind CSS in your global styles. Update your `globals.css` file:
```css
@tailwind base;
@tailwind components;
@tailwind utilities;
```

You can also fine-tune the typography by including the Tailwind Typography plugin for better formatting of MDX content:
```bash
npm install @tailwindcss/typography
```
Then add it to your `tailwind.config.js`:
```js
plugins: [require("@tailwindcss/typography")],
```

Now, add the `prose` class to your components that render MDX content for beautifully styled markdown.

---

These steps should give you a solid foundation for your documentation site. Let me know if you need more help or further customization tips!

Great question! To display a Table of Contents (ToC) based on the headings in your MDX files, you can use a library like `rehype-toc` or manually parse the headings during the MDX serialization process. Here's how you can do it step by step:

### 1. Install Necessary Libraries
First, you'll need `rehype-slug` and `rehype-toc` to generate unique IDs for headings and build the Table of Contents:
```bash
npm install rehype-slug rehype-autolink-headings rehype-toc
```

### 2. Update MDX Serialization
Modify your `getStaticProps` function to include a Table of Contents during the serialization process. Here’s an updated version:
```tsx
import rehypeSlug from "rehype-slug";
import rehypeAutolinkHeadings from "rehype-autolink-headings";
import rehypeToc from "rehype-toc";
import { serialize } from "next-mdx-remote/serialize";

export const getStaticProps: GetStaticProps = async ({ params }) => {
  const slug = params?.slug as string;
  const filePath = path.join(DOCS_PATH, `${slug}.mdx`);
  const source = fs.readFileSync(filePath, "utf8");
  const { content, data } = matter(source);

  let toc = [];

  const mdxSource = await serialize(content, {
    mdxOptions: {
      rehypePlugins: [
        rehypeSlug,
        rehypeAutolinkHeadings,
        [rehypeToc, { headings: ["h1", "h2", "h3"], customizeTOC: (tocTree) => {
            toc = tocTree; // Store ToC for later use
          } }]
      ],
    },
  });

  return {
    props: {
      source: mdxSource,
      frontMatter: data,
      toc,
    },
  };
};
```

### 3. Create a ToC Component
Now we need to render the Table of Contents using the `toc` data passed as props. Add a `TableOfContents` component in your `components` folder:
```tsx
interface TOCItem {
  id: string;
  title: string;
  level: number;
  children?: TOCItem[];
}

const renderTOC = (toc: TOCItem[]) => {
  return (
    <ul className="space-y-2">
      {toc.map((item) => (
        <li key={item.id} className={`pl-${item.level * 4} text-sm`}>
          <a href={`#${item.id}`} className="text-blue-600 hover:underline">
            {item.title}
          </a>
          {item.children && renderTOC(item.children)}
        </li>
      ))}
    </ul>
  );
};

const TableOfContents = ({ toc }: { toc: TOCItem[] }) => {
  return (
    <nav className="border-l-2 border-gray-200 pl-4">
      <h2 className="font-bold mb-4">Table of Contents</h2>
      {renderTOC(toc)}
    </nav>
  );
};

export default TableOfContents;
```

### 4. Use the ToC Component on the Page
In your `[slug].tsx` file, pass the `toc` prop to the `TableOfContents` component:
```tsx
import TableOfContents from "../components/TableOfContents";

const DocPage = ({ source, frontMatter, toc }: { source: MDXRemoteSerializeResult; frontMatter: any; toc: any }) => {
  return (
    <div className="prose mx-auto mt-8 flex">
      <div className="w-3/4">
        <h1>{frontMatter.title}</h1>
        <MDXRemote {...source} />
      </div>
      <div className="w-1/4 pl-8">
        <TableOfContents toc={toc} />
      </div>
    </div>
  );
};

export default DocPage;
```

### 5. Style the ToC
Finally, use Tailwind CSS to style the ToC for better presentation. Add the following styles in your component:
```css
.nav-link {
  display: block;
  margin-bottom: 0.5rem;
  color: #1d4ed8;
  text-decoration: none;
}

.nav-link:hover {
  text-decoration: underline;
}
```
---

That's it! When you navigate to a documentation page, the Table of Contents will be dynamically generated based on the headings in your MDX content. Let me know if you need further help or additional features!

I'm glad you found the previous instructions helpful! Adding a search feature to your documentation site is a fantastic way to improve its usability. Here’s how you can implement a simple search functionality using `Fuse.js`, a lightweight search library.

---

### 1. Install Fuse.js
First, add the `fuse.js` package to your project:
```bash
npm install fuse.js
```

### 2. Index Your MDX Files
To enable search, you’ll need to create a single index of all your MDX content. You can build this during the `getStaticProps` phase.

Update your `[slug].tsx` file to look like this:

```tsx
import fs from "fs";
import path from "path";
import matter from "gray-matter";
import Fuse from "fuse.js";
import { GetStaticProps } from "next";
import Layout from "../components/layout";

const DOCS_PATH = path.join(process.cwd(), "docs");

export const getStaticProps: GetStaticProps = async () => {
  const filenames = fs.readdirSync(DOCS_PATH);
  const allDocs = filenames.map((filename) => {
    const filePath = path.join(DOCS_PATH, filename);
    const source = fs.readFileSync(filePath, "utf8");
    const { content, data } = matter(source);

    return {
      slug: filename.replace(/\.mdx?$/, ""),
      title: data.title || filename,
      content,
    };
  });

  return {
    props: {
      allDocs,
    },
  };
};

const DocumentationSearch = ({ allDocs }: { allDocs: any[] }) => {
  // Initialize Fuse.js for searching
  const fuse = new Fuse(allDocs, {
    keys: ["title", "content"],
    includeMatches: true,
    threshold: 0.3, // Adjust this for search sensitivity
  });

  const [query, setQuery] = React.useState("");
  const [results, setResults] = React.useState([]);

  const handleSearch = (e: React.ChangeEvent<HTMLInputElement>) => {
    const searchQuery = e.target.value;
    setQuery(searchQuery);
    const searchResults = fuse.search(searchQuery);
    setResults(searchResults.map((result) => result.item));
  };

  return (
    <Layout>
      <div className="mx-auto max-w-4xl">
        <h1 className="text-3xl font-bold mb-4">Search Documentation</h1>

        {/* Search Input */}
        <input
          type="text"
          placeholder="Search..."
          value={query}
          onChange={handleSearch}
          className="w-full border border-gray-300 rounded-md p-2 mb-4"
        />

        {/* Search Results */}
        {results.length > 0 ? (
          <ul className="list-disc pl-5">
            {results.map((doc) => (
              <li key={doc.slug}>
                <a href={`/docs/${doc.slug}`} className="text-blue-600 hover:underline">
                  {doc.title}
                </a>
              </li>
            ))}
          </ul>
        ) : query && (
          <p>No results found for "{query}".</p>
        )}
      </div>
    </Layout>
  );
};

export default DocumentationSearch;
```

### 3. Add Routing to the Search Page
You can create a new page, e.g., `pages/search.tsx`, and import the `DocumentationSearch` component as the default export for that route.

```tsx
import DocumentationSearch from "../components/DocumentationSearch";
export { getStaticProps } from "../components/DocumentationSearch";

export default DocumentationSearch;
```

### 4. Add a Search Input to Your Layout
If you want the search bar to be visible on every page, modify your `components/layout.tsx` file to include a link to the search page or embed the search bar directly:
```tsx
import Link from "next/link";

const Layout = ({ children }: { children: React.ReactNode }) => {
  return (
    <div>
      <header className="bg-gray-800 p-4 text-white">
        <div className="container mx-auto flex justify-between">
          <Link href="/">
            <a className="text-lg font-bold">My Docs Site</a>
          </Link>
          <Link href="/search">
            <a className="text-blue-300">Search</a>
          </Link>
        </div>
      </header>
      <main className="p-4">{children}</main>
    </div>
  );
};

export default Layout;
```

---

### Bonus: Improving Search Experience
1. **Highlight Matches:** You can use the `matches` property from `fuse.search()` results to highlight the search term in the results.
2. **Client-Side Search:** If your documentation grows large, you might want to fetch the search index on the frontend and perform searching entirely on the client side instead of during the build process.
3. **Search Styling:** Use Tailwind classes to make the search input and results visually appealing and aligned with your site's theme.

