```groovy
pipeline {
    agent any

    environment {
        DOCKER_CREDENTIALS_ID = 'your-docker-credentials-id' // Set up credentials in Jenkins
        IMAGE_NAME = 'your-docker-image-name'
        IMAGE_TAG = 'latest'
        REGISTRY = 'dockerhub-username'
    }

    stages {
        stage('Checkout') {
            steps {
                // Fetch the code from your version control system
                checkout scm
            }
        }

        stage('Build Docker Image') {
            steps {
                script {
                    // Build the Docker image
                    sh "docker build -t ${REGISTRY}/${IMAGE_NAME}:${IMAGE_TAG} ."
                }
            }
        }

        stage('Push to Docker Registry') {
            steps {
                script {
                    // Log in to Docker Registry
                    withCredentials([usernamePassword(credentialsId: env.DOCKER_CREDENTIALS_ID, usernameVariable: 'DOCKER_USER', passwordVariable: 'DOCKER_PASS')]) {
                        sh "echo $DOCKER_PASS | docker login -u $DOCKER_USER --password-stdin"
                    }

                    // Push the Docker image
                    sh "docker push ${REGISTRY}/${IMAGE_NAME}:${IMAGE_TAG}"
                }
            }
        }
    }

    post {
        always {
            // Cleanup Docker images on the Jenkins agent to save space
            sh 'docker system prune -f'
        }
    }
}
```

### Key Points:
1. **Environment Variables**: Use environment variables for flexibility, such as the image name, tag, and registry.
2. **Docker Credentials**: Store your Docker Hub or registry credentials in Jenkins Credentials Manager. Reference them in your pipeline using `withCredentials`.
3. **Build and Push Commands**: Use `docker build` to build the image and `docker push` to push it to the registry.
4. **Cleanup**: Clean up unused Docker resources after each build to prevent storage issues.

